.pipeline-inbox-body.open { display: flex; }
.pipeline-inbox-body::-webkit-scrollbar { width: 4px; }
.pipeline-inbox-body::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }
.inbox-section-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--text3);
  text-transform: uppercase;
  letter-spacing: 0.07em;
  padding: 6px 0 4px;
}
.inbox-card {
  background: var(--surface2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 11px 12px;
  display: flex;
  gap: 12px;
  align-items: flex-start;
  transition: border-color 0.15s;
}
.inbox-card:hover { border-color: var(--border2); }
.inbox-card-left { flex: 1; min-width: 0; }
.inbox-deal-name {
  font-size: 12px;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 2px;
}
.inbox-buyer {
  font-size: 11px;
  color: var(--text3);
  margin-bottom: 5px;
}
.inbox-reply-snippet {
  font-size: 11px;
  color: var(--text2);
