function openBulkSend() {
  const drafts = pipeline['draft_ready'] || [];
  if (!drafts.length) {
    showToast('No Draft Ready records to send', 3000);
    return;
  }

  document.getElementById('pl-bulk-count').textContent =
    `${drafts.length} email${drafts.length !== 1 ? 's' : ''} ready to send:`;

  document.getElementById('pl-bulk-list').innerHTML = drafts.map(r =>
    `<div class="pl-bulk-recipient">
      <span class="pl-bulk-rname">${esc(r.buyer_name || 'Unknown')}</span>
      <span class="pl-bulk-remail">${esc(r.buyer_email || '—')}</span>
      <span class="pl-bulk-rdeal">${esc(r.deal_name || r.title || '')}</span>
    </div>`
  ).join('');

  // Reset progress UI
  document.getElementById('pl-bulk-progress').style.display   = 'none';
  document.getElementById('pl-bulk-bar').style.width          = '0%';
  document.getElementById('pl-bulk-progress-text').textContent = '';
  document.getElementById('pl-bulk-confirm-btn').style.display = '';
  document.getElementById('pl-bulk-cancel-btn').style.display  = '';
  document.getElementById('pl-bulk-close-btn').style.display   = '';
  plBulkSending = false;

  document.getElementById('pl-bulk-modal').classList.add('active');
}

function closeBulkSendModal() {
  if (plBulkSending) return;
  document.getElementById('pl-bulk-modal').classList.remove('active');
}

async function confirmBulkSend() {
  const drafts = (pipeline['draft_ready'] || []).slice();
  if (!drafts.length) return;

  plBulkSending = true;
  const confirmBtn  = document.getElementById('pl-bulk-confirm-btn');
  const cancelBtn   = document.getElementById('pl-bulk-cancel-btn');
  const closeBtn    = document.getElementById('pl-bulk-close-btn');
  const progressEl  = document.getElementById('pl-bulk-progress');
  const bar         = document.getElementById('pl-bulk-bar');
  const progressTxt = document.getElementById('pl-bulk-progress-text');

  confirmBtn.style.display = 'none';
  cancelBtn.style.display  = 'none';
  closeBtn.style.display   = 'none';
  progressEl.style.display = '';
  progressTxt.textContent  = `Sending ${drafts.length} emails…`;
  bar.style.width = '10%';

  const total = drafts.length;
  let succeeded = 0, failed = 0;
  const failedNames = [];

  try {
    // Primary: bulk send endpoint — sends all draft_ready records in one call
    const resp = await fetch('/api/pipeline/send-all', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ ids: drafts.map(r => r.id) }),
    });
    if (resp.ok) {
      const data = await resp.json();
      // Server may return { sent, failed, errors } or just { sent }
      succeeded = data.sent  ?? total;
      failed    = data.failed ?? 0;
      if (Array.isArray(data.errors)) {
        data.errors.forEach(e => failedNames.push(e.name || e.id || 'unknown'));
      }
      bar.style.width = '100%';
      progressTxt.textContent = `Sent ${succeeded} of ${total}`;
    } else {
      // Fallback: send per-record if bulk endpoint fails
      throw new Error(`HTTP ${resp.status}`);
    }
  } catch (_bulkErr) {
    // Fallback: iterate individually
    for (const r of drafts) {
      const sent = succeeded + failed + 1;
      progressTxt.textContent = `Sending ${sent} of ${total}… ${esc(r.buyer_name || r.id)}`;
      try {
        const resp = await fetch(`/api/pipeline/${encodeURIComponent(r.id)}/send`, {
          method:  'POST',
          headers: { 'Content-Type': 'application/json' },
        });
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        succeeded++;
      } catch (e) {
        failed++;
        failedNames.push(r.buyer_name || r.id);
      }
      bar.style.width = `${Math.round((succeeded + failed) / total * 100)}%`;
    }
  }

  plBulkSending = false;
  document.getElementById('pl-bulk-modal').classList.remove('active');

  const preview = failedNames.slice(0, 3).join(', ') + (failedNames.length > 3 ? '…' : '');
  const summary = failed === 0
    ? `✓ All ${succeeded} emails sent successfully`
    : `Sent ${succeeded} of ${total} · ${failed} failed: ${preview}`;
  showToast(summary, failed > 0 ? 7000 : 4000);

  await loadPipeline();
}

// ================================================================
// PIPELINE — Inbox Section
// ================================================================
function togglePipelineInbox() {
  pipelineInboxOpen = !pipelineInboxOpen;
  const body    = document.getElementById('pipeline-inbox-body');
  const chevron = document.getElementById('pipeline-inbox-chevron');
  body.classList.toggle('open', pipelineInboxOpen);
  chevron.classList.toggle('open', pipelineInboxOpen);
  if (pipelineInboxOpen) renderPipelineInbox();
}

function renderPipelineInbox() {
  const body  = document.getElementById('pipeline-inbox-body');
  const badge = document.getElementById('pipeline-inbox-badge');
  if (!body) return;

  const replied  = pipeline['replied']         || [];
  const followUp = pipeline['follow_up_draft'] || [];
  const count    = replied.length + followUp.length;

  if (badge) {
    badge.textContent = count;
    badge.classList.toggle('empty', count === 0);
  }

  if (!pipelineInboxOpen) return;

  if (!count) {
    body.innerHTML =
      '<div style="color:var(--text3);font-size:12px;padding:6px 0">No replies or follow-up drafts.</div>';
    return;
  }

  const parts = [];

  if (replied.length) {
    parts.push(`<div class="inbox-section-label">Replies (${replied.length})</div>`);
    replied.forEach(r => parts.push(plInboxCard(r, 'replied')));
  }

  if (followUp.length) {
    parts.push(`<div class="inbox-section-label" style="padding-top:10px">Follow-Up Drafts (${followUp.length})</div>`);
    followUp.forEach(r => parts.push(plInboxCard(r, 'follow_up_draft')));
  }

  body.innerHTML = parts.join('');
}

function plInboxCard(r, stageKey) {
  const id       = esc(r.id);
  const dealName = r.deal_name || r.title || '(Unnamed Deal)';
  const snippet  = stageKey === 'replied'
    ? (r.reply_body || r.reply || r.reply_text || '')
    : (r.email_body || '');

  const actions = stageKey === 'replied'
    ? `<button class="pipeline-btn pipeline-btn-sm" onclick="openReplyModal('${id}')">View Reply</button>
       <button class="pipeline-btn pipeline-btn-sm pipeline-btn-primary" onclick="draftFollowUp('${id}',this)">Draft Follow-Up</button>`
    : `<button class="pipeline-btn pipeline-btn-sm" onclick="openPipelineEdit('${id}')">✏️ Edit</button>
       <button class="pipeline-btn pipeline-btn-sm pipeline-btn-primary" onclick="confirmSingleSend('${id}')">✅ Send</button>`;

  return `<div class="inbox-card">
    <div class="inbox-card-left">
      <div class="inbox-deal-name">${esc(dealName)}</div>
      <div class="inbox-buyer">${esc(r.buyer_name || '')}${r.buyer_email ? ' · ' + esc(r.buyer_email) : ''}</div>
      ${snippet ? `<div class="inbox-reply-snippet">${esc(snippet)}</div>` : ''}
    </div>
    <div class="inbox-card-actions">${actions}</div>
  </div>`;
}

async function checkPipelineInbox() {
  try {
    const r = await fetch('/api/pipeline/inbox-check');
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    const data = await r.json();
    const newReplies = data.new_replies ?? data.count ?? 0;
    showToast(newReplies > 0
      ? `Inbox: ${newReplies} new repl${newReplies !== 1 ? 'ies' : 'y'} found ✓`
      : 'Inbox checked — no new replies');
    await loadPipeline();
  } catch (e) {
    showToast(`Inbox check failed: ${e.message}`, 5000);
  }
}

// ================================================================
// PIPELINE — Extend switchView to handle 'pipeline'
// ================================================================
(function patchSwitchView() {
  const _orig = switchView;

  switchView = function(view, dept, agent) {
    const pipelineEl = document.getElementById('view-pipeline');

    if (view === 'pipeline') {
      // Deactivate all existing views
      ['board','departments','dept-detail','agent-board'].forEach(v => {
        document.getElementById(`view-${v}`)?.classList.remove('active');
      });
      pipelineEl?.classList.add('active');

      // Nav highlight
      document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
      document.querySelector('.nav-item[data-view="pipeline"]')?.classList.add('active');

      // Hide KPI bar and breadcrumb (not relevant for pipeline)
      document.getElementById('kpi-bar')?.classList.add('hidden');
      document.getElementById('breadcrumb-bar')?.classList.add('hidden');

      currentView = 'pipeline';
      loadPipeline();
      return;
    }

    // Ensure pipeline view is hidden for all other views
    pipelineEl?.classList.remove('active');
    _orig.call(this, view, dept, agent);
  };
})();
